from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np

app = Flask(__name__)

# In-memory storage for image labels and annotations
image_labels = {}
annotations = {}

@app.route('/submit_annotation', methods=['POST'])
def submit_annotation():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    
    if image_id not in annotations:
        annotations[image_id] = []
    
    annotations[image_id].append(label)
    
    return jsonify({"status": "success"}), 200

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    
    for image_id, labels in annotations.items():
        most_common_label = max(set(labels), key=labels.count)
        aggregated_labels[image_id] = most_common_label
    
    return jsonify(aggregated_labels), 200

@app.route('/train_model', methods=['POST'])
def train_model():
    # Dummy model training logic for demonstration purposes
    data = request.json
    X_train = np.array(data['X_train'])  # Feature vectors
    y_train = np.array(data['y_train'])  # Labels
    
    # Simple majority voting as a proxy for training
    unique_labels, counts = np.unique(y_train, return_counts=True)
    most_common_label = unique_labels[np.argmax(counts)]
    
    print(f"Model trained with majority class: {most_common_label}")
    
    return jsonify({"trained_with_class": str(most_common_label)}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)